const { chromium } = require('playwright');
const path = require('path');

const SCREENSHOTS_DIR = path.resolve('C:/Users/User/nexus-ai/test-screenshots');
const BASE_URL = 'https://nexus-ai-silk-six.vercel.app';

(async () => {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1280, height: 900 },
  });
  const page = await context.newPage();

  // Listen for console messages and errors
  page.on('console', msg => {
    if (msg.type() === 'error') {
      console.log(`[CONSOLE ERROR] ${msg.text()}`);
    }
  });
  page.on('pageerror', err => {
    console.log(`[PAGE ERROR] ${err.message}`);
  });

  try {
    // ============================================================
    // STEP 1: SIGNUP PAGE
    // ============================================================
    console.log('\n=== STEP 1: Navigate to Signup Page ===');
    const signupResponse = await page.goto(`${BASE_URL}/signup`, {
      waitUntil: 'networkidle',
      timeout: 30000,
    });
    console.log(`Signup page status: ${signupResponse.status()}`);
    console.log(`Signup page URL: ${page.url()}`);

    // STEP 2: Screenshot of signup page
    console.log('\n=== STEP 2: Screenshot of Signup Page ===');
    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, '01-signup-page.png'),
      fullPage: true,
    });
    console.log('Screenshot saved: 01-signup-page.png');

    // STEP 3: Fill in the signup form
    console.log('\n=== STEP 3: Fill in Signup Form ===');

    // Log all input fields visible on the page
    const signupInputs = await page.evaluate(() => {
      const inputs = document.querySelectorAll('input, button[type="submit"], button');
      return Array.from(inputs).map(el => ({
        tag: el.tagName,
        type: el.type || '',
        name: el.name || '',
        id: el.id || '',
        placeholder: el.placeholder || '',
        text: el.textContent?.trim().substring(0, 50) || '',
        ariaLabel: el.getAttribute('aria-label') || '',
      }));
    });
    console.log('Form elements found:', JSON.stringify(signupInputs, null, 2));

    // Try to fill Full Name
    try {
      const nameSelector = 'input[name="name"], input[name="fullName"], input[name="full_name"], input[placeholder*="name" i], input[placeholder*="Name" i], input[id*="name" i], input[type="text"]:first-of-type';
      await page.waitForSelector(nameSelector, { timeout: 5000 });
      await page.fill(nameSelector, 'Test User');
      console.log('Filled Full Name: "Test User"');
    } catch (e) {
      console.log(`Could not fill name field: ${e.message}`);
    }

    // Try to fill Email
    try {
      const emailSelector = 'input[name="email"], input[type="email"], input[placeholder*="email" i], input[id*="email" i]';
      await page.waitForSelector(emailSelector, { timeout: 5000 });
      await page.fill(emailSelector, 'testuser@nexusai-test.com');
      console.log('Filled Email: "testuser@nexusai-test.com"');
    } catch (e) {
      console.log(`Could not fill email field: ${e.message}`);
    }

    // Try to fill Password
    try {
      const passwordSelector = 'input[name="password"], input[type="password"], input[placeholder*="password" i], input[id*="password" i]';
      await page.waitForSelector(passwordSelector, { timeout: 5000 });
      await page.fill(passwordSelector, 'TestPassword123!');
      console.log('Filled Password: "TestPassword123!"');
    } catch (e) {
      console.log(`Could not fill password field: ${e.message}`);
    }

    // Screenshot after filling form
    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, '02-signup-form-filled.png'),
      fullPage: true,
    });
    console.log('Screenshot saved: 02-signup-form-filled.png');

    // STEP 4: Click "Create account"
    console.log('\n=== STEP 4: Click Create Account ===');
    try {
      const createAccountBtn = page.locator('button:has-text("Create account"), button:has-text("Sign up"), button:has-text("Register"), button[type="submit"]').first();
      await createAccountBtn.click();
      console.log('Clicked Create Account button');

      // STEP 5: Wait for result
      console.log('\n=== STEP 5: Wait for Result ===');
      await page.waitForTimeout(3000);
      // Also try to wait for navigation
      try {
        await page.waitForURL((url) => url.toString() !== `${BASE_URL}/signup`, { timeout: 5000 });
        console.log(`Navigated to: ${page.url()}`);
      } catch (e) {
        console.log(`Still on signup page after submit. URL: ${page.url()}`);
      }
    } catch (e) {
      console.log(`Could not click Create Account: ${e.message}`);
    }

    // Check for error messages on page
    const signupMessages = await page.evaluate(() => {
      const alerts = document.querySelectorAll('[role="alert"], .error, .alert, .message, .toast, [class*="error"], [class*="alert"], [class*="toast"], [class*="message"]');
      return Array.from(alerts).map(el => el.textContent?.trim()).filter(Boolean);
    });
    if (signupMessages.length > 0) {
      console.log('Messages on page after signup attempt:', signupMessages);
    }

    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, '03-signup-result.png'),
      fullPage: true,
    });
    console.log('Screenshot saved: 03-signup-result.png');

    // ============================================================
    // STEP 6: LOGIN PAGE
    // ============================================================
    console.log('\n=== STEP 6: Navigate to Login Page ===');
    const loginResponse = await page.goto(`${BASE_URL}/login`, {
      waitUntil: 'networkidle',
      timeout: 30000,
    });
    console.log(`Login page status: ${loginResponse.status()}`);
    console.log(`Login page URL: ${page.url()}`);

    // STEP 7: Screenshot of login page
    console.log('\n=== STEP 7: Screenshot of Login Page ===');
    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, '04-login-page.png'),
      fullPage: true,
    });
    console.log('Screenshot saved: 04-login-page.png');

    // Log all input fields on login page
    const loginInputs = await page.evaluate(() => {
      const inputs = document.querySelectorAll('input, button[type="submit"], button');
      return Array.from(inputs).map(el => ({
        tag: el.tagName,
        type: el.type || '',
        name: el.name || '',
        id: el.id || '',
        placeholder: el.placeholder || '',
        text: el.textContent?.trim().substring(0, 50) || '',
      }));
    });
    console.log('Login form elements:', JSON.stringify(loginInputs, null, 2));

    // STEP 8: Fill login form
    console.log('\n=== STEP 8: Fill Login Form ===');
    try {
      const emailSelector = 'input[name="email"], input[type="email"], input[placeholder*="email" i], input[id*="email" i]';
      await page.waitForSelector(emailSelector, { timeout: 5000 });
      await page.fill(emailSelector, 'testuser@nexusai-test.com');
      console.log('Filled Email: "testuser@nexusai-test.com"');
    } catch (e) {
      console.log(`Could not fill email field: ${e.message}`);
    }

    try {
      const passwordSelector = 'input[name="password"], input[type="password"], input[placeholder*="password" i], input[id*="password" i]';
      await page.waitForSelector(passwordSelector, { timeout: 5000 });
      await page.fill(passwordSelector, 'TestPassword123!');
      console.log('Filled Password: "TestPassword123!"');
    } catch (e) {
      console.log(`Could not fill password field: ${e.message}`);
    }

    // Screenshot after filling login form
    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, '05-login-form-filled.png'),
      fullPage: true,
    });
    console.log('Screenshot saved: 05-login-form-filled.png');

    // STEP 9: Click Sign In
    console.log('\n=== STEP 9: Click Sign In ===');
    try {
      const signInBtn = page.locator('button:has-text("Sign in"), button:has-text("Log in"), button:has-text("Login"), button[type="submit"]').first();
      await signInBtn.click();
      console.log('Clicked Sign In button');

      // STEP 10: Wait for navigation
      console.log('\n=== STEP 10: Wait for Navigation ===');
      await page.waitForTimeout(3000);
      try {
        await page.waitForURL((url) => url.toString() !== `${BASE_URL}/login`, { timeout: 5000 });
        console.log(`Navigated to: ${page.url()}`);
      } catch (e) {
        console.log(`Still on login page after submit. URL: ${page.url()}`);
      }
    } catch (e) {
      console.log(`Could not click Sign In: ${e.message}`);
    }

    // Check for error/success messages
    const loginMessages = await page.evaluate(() => {
      const alerts = document.querySelectorAll('[role="alert"], .error, .alert, .message, .toast, [class*="error"], [class*="alert"], [class*="toast"], [class*="message"]');
      return Array.from(alerts).map(el => el.textContent?.trim()).filter(Boolean);
    });
    if (loginMessages.length > 0) {
      console.log('Messages on page after login attempt:', loginMessages);
    }

    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, '06-login-result.png'),
      fullPage: true,
    });
    console.log('Screenshot saved: 06-login-result.png');

    // ============================================================
    // STEP 11: FORGOT PASSWORD PAGE
    // ============================================================
    console.log('\n=== STEP 11: Navigate to Forgot Password Page ===');
    const forgotResponse = await page.goto(`${BASE_URL}/forgot-password`, {
      waitUntil: 'networkidle',
      timeout: 30000,
    });
    console.log(`Forgot Password page status: ${forgotResponse.status()}`);
    console.log(`Forgot Password page URL: ${page.url()}`);

    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, '07-forgot-password-page.png'),
      fullPage: true,
    });
    console.log('Screenshot saved: 07-forgot-password-page.png');

    // Log elements on forgot password page
    const forgotInputs = await page.evaluate(() => {
      const inputs = document.querySelectorAll('input, button[type="submit"], button');
      return Array.from(inputs).map(el => ({
        tag: el.tagName,
        type: el.type || '',
        name: el.name || '',
        placeholder: el.placeholder || '',
        text: el.textContent?.trim().substring(0, 50) || '',
      }));
    });
    console.log('Forgot Password form elements:', JSON.stringify(forgotInputs, null, 2));

    console.log('\n=== ALL TESTS COMPLETED ===');
    console.log(`Screenshots saved to: ${SCREENSHOTS_DIR}`);

  } catch (error) {
    console.error(`\n!!! FATAL ERROR: ${error.message}`);
    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, 'error-screenshot.png'),
      fullPage: true,
    });
    console.log('Error screenshot saved.');
  } finally {
    await browser.close();
  }
})();

